CREATE TABLE IF NOT EXISTS gda_action_items (
  id SERIAL PRIMARY KEY,
  item VARCHAR(1000),
  owner VARCHAR(100) DEFAULT 'GDA AI',
  deadline DATE,
  status VARCHAR(50) DEFAULT 'Open',
  source_meeting VARCHAR(255),
  created_at TIMESTAMP DEFAULT NOW()
);
SELECT * FROM gda_action_items ORDER BY created_at DESC LIMIT 50;

