  entity_type: 'daily_actions',
  entity_id: null,
  predicted_value: null,
  actual_value: $json.action_count,
  signal: 'daily_actions_generated',
  context: {
    action_count: $json.action_count,
    categories: $json.actions ? [...new Set($json.actions.map(a => a.category))].join(',') : '',
    urgency_breakdown: $json.actions ? {
      urgent: $json.actions.filter(a => a.urgency === 'URGENT').length,
      high: $json.actions.filter(a => a.urgency === 'HIGH').length,
      medium: $json.actions.filter(a => a.urgency === 'MEDIUM').length
    } : {}
  },
  source: 'daily-actions'
}) }}
